What does this program print?

```cpp
#include <iostream>
#include <memory>

struct R {
    ~R() { std::cout << "gone\n"; }
};

int main() {
    std::shared_ptr<R> a = std::make_shared<R>();
    std::weak_ptr<R>   w = a;
    a.reset();
    if (w.lock()) std::cout << "alive\n";
    else          std::cout << "dead\n";
    return 0;
}
```

