```cpp
#include <iostream>
#include <memory>

void take(std::unique_ptr<int> p) {
    std::cout << *p << "\n";
}

int main() {
    auto p = std::make_unique<int>(55);
    take(std::move(p));
    std::cout << (p ? "has value" : "null") << "\n";
    return 0;
}
